EOT;

        $lines = explode("\n", trim($tsvData));
        $insertData = [];

        foreach ($lines as $line) {
            $cols = explode("|", trim($line));

            // Pastikan baris memiliki data yang cukup (mencegah error baris kosong)
            if (count($cols) < 38)
                continue;

            // 1. Parsing Tanggal Lahir
            $tglLahir = $this->parseDate($cols[6]);

            // 2. Ekstrak TMT CPNS dari NIP (Format NIP PNS: YYYYMMDD YYYYMM C OOO)
            $tmtCpns = null;
            $cleanNip = str_replace(' ', '', $cols[2]);
            if (strlen($cleanNip) >= 14 && is_numeric(substr($cleanNip, 0, 14))) {
                $yearCpns = substr($cleanNip, 8, 4);
                $monthCpns = substr($cleanNip, 12, 2);
                if ($yearCpns > 1950 && $monthCpns > 0 && $monthCpns <= 12) {
                    $tmtCpns = "$yearCpns-$monthCpns-01";
                }
            }

            // 3. Bezetting ID
            // Nama jabatan ada di index ke-29 pada TSV
            $bezettingId = Bezetting::where('nama_jabatan', 'like', '%' . trim($cols[29]) . '%')
                ->value('id');

            // 4. Mapping Status Pernikahan ke Enum
            $rawStatusPernikahan = trim($cols[11]);
            $statusPernikahan = match ($rawStatusPernikahan) {
                    'Menikah' => \App\Enums\StatusPernikahan::KAWIN->value,
                    'Belum Menikah' => \App\Enums\StatusPernikahan::BELUM_KAWIN->value,
                    'Janda', 'Duda', 'Cerai Hidup', 'Cerai Mati' => \App\Enums\StatusPernikahan::CERAI_MATI->value,
                    default => null,
                };

            // 5. Mapping Agama ke Enum
            $rawAgama = trim($cols[10]);
            $agama = match ($rawAgama) {
                    'Kristen/Protestan' => \App\Enums\Agama::KRISTEN_PROTESTAN->value,
                    'Katholik', 'Katolik' => \App\Enums\Agama::KATOLIK->value,
                    'Budha', 'Buddha' => \App\Enums\Agama::BUDDHA->value,
                    default => $rawAgama,
                };

            // Memasukkan ke array untuk Insert Batch
            $insertData[] = [
                'nip' => $cleanNip,
                'nama_lengkap' => trim($cols[1]),
                'tempat_lahir' => trim($cols[5]),
                'tanggal_lahir' => $tglLahir,
                'jenis_kelamin' => trim($cols[9]) === 'L' ? 'L' : 'P',
                'agama' => $agama,
                'pendidikan_terakhir' => trim($cols[23]),
                'status_pegawai' => trim($cols[17]), // CPNS, PNS, PPPK, dll.

                // Bezetting ID dibiarkan null dulu agar tidak konflik foreign key
                'bezetting_id' => $bezettingId,

                'pangkat_golongan' => trim($cols[20]),
                'tmt_cpns' => $tmtCpns,
                'bup' => 0,
                'status_kedudukan' => trim($cols[18]) ?: 'Aktif',
                'nik' => str_replace(' ', '', $cols[7]),
                'status_pernikahan' => $statusPernikahan,
                'alamat' => trim($cols[12]),
                'tmt_pns' => null, // Data TSV belum ada explicit tmt_pns
                'unit_kerja' => trim($cols[37] ?? ''),
                'skpd' => trim($cols[38] ?? ''),

                // Status langsung di-set ke final karena ini data riil
                'status' => 'final',
                'created_at' => $now,
                'updated_at' => $now,
            ];
        }

        // Insert ke database
        DB::table('pegawais')->insert($insertData);
    }

    /**
     * Helper untuk mengonversi format "08-08-80" menjadi "1980-08-08"
     */
    private function parseDate($dateStr)
    {
        $dateStr = trim($dateStr);
        if (empty($dateStr) || $dateStr === '--' || $dateStr === '-')
            return null;

        $parts = explode('-', $dateStr);
        if (count($parts) === 3) {
            $year = (int)$parts[2];
            // Logika: Jika tahun di atas 30 berarti 19xx, jika di bawahnya 20xx
            $year = $year > 30 ? 1900 + $year : 2000 + $year;
            return sprintf('%04d-%02d-%02d', $year, $parts[1], $parts[0]);
        }

        return null;
    }
}